/*!
 * html5-qrcode 本地化兜底（DESIGN v2.0 REVIEW 1.6）
 *
 * 使用浏览器原生 BarcodeDetector API（Chrome 83+/Edge 83+/Safari 16+）
 * 不支持时降级为手动输入
 *
 * 暴露与 html5-qrcode 兼容的 API：
 *   new Html5Qrcode(elementId)
 *   .start({facingMode: 'environment'}, {fps, qrbox}, onSuccess, onError)
 *   .stop()
 */
(function (root) {
  'use strict';

  function Html5Qrcode(elementId) {
    this.elementId = elementId;
    this.video = null;
    this.stream = null;
    this.detector = null;
    this.interval = null;
    this.scanning = false;
  }

  Html5Qrcode.prototype._supported = function () {
    return !!(navigator.mediaDevices && navigator.mediaDevices.getUserMedia && window.BarcodeDetector);
  };

  Html5Qrcode.prototype.start = function (config, qrbox, onSuccess, onError) {
    var self = this;
    var fps = (qrbox && qrbox.fps) || 10;
    var el = document.getElementById(this.elementId);
    if (!el) { onError && onError(new Error('element not found')); return Promise.reject(new Error('element not found')); }

    // 修复 M-5：不要用 innerHTML 注入 <video>（保留静态结构 + 设置 textContent）
    el.textContent = '';
    var video = document.createElement('video');
    video.autoplay = true;
    video.playsInline = true;
    video.muted = true;
    video.style.width = '100%';
    video.style.maxWidth = '500px';
    video.style.border = '1px solid #ccc';
    el.appendChild(video);

    if (!this._supported()) {
      // 修复 M-5：用 textContent + 单独元素，不用 innerHTML 拼接
      el.textContent = '';
      var warn = document.createElement('div');
      warn.className = 'alert alert-warning';
      warn.textContent = '当前浏览器不支持原生扫码（BarcodeDetector）。请使用手动输入。';
      el.appendChild(warn);
      return Promise.reject(new Error('BarcodeDetector not supported'));
    }

    this.video = el.querySelector('video');
    var facingMode = (config && config.facingMode) || 'environment';

    return navigator.mediaDevices.getUserMedia({ video: { facingMode: facingMode } })
      .then(function (stream) {
        self.stream = stream;
        self.video.srcObject = stream;
        self.detector = new BarcodeDetector({ formats: ['qr_code', 'code_128', 'code_39', 'ean_13'] });
        self.scanning = true;

        self.interval = setInterval(function () {
          if (!self.scanning) return;
          self.detector.detect(self.video).then(function (codes) {
            if (codes && codes.length) {
              // 修复 M-5：包 try/catch，onSuccess 异常不终止 setInterval
              try {
                onSuccess && onSuccess(codes[0].rawValue);
              } catch (e) {
                console.error('[Html5Qrcode] onSuccess handler error:', e);
              }
            }
          }).catch(function () {
            // ignore detect errors
          });
        }, 1000 / fps);
      })
      .catch(function (err) {
        // 修复 M-5：用 textContent 替代 innerHTML 拼接 err.message（避免 XSS）
        el.textContent = '';
        var errDiv = document.createElement('div');
        errDiv.className = 'alert alert-warning';
        // err.message 可能含 HTML 字符，textContent 自动转义
        var prefix = document.createTextNode('摄像头不可用：');
        errDiv.appendChild(prefix);
        errDiv.appendChild(document.createTextNode(err && err.message ? err.message : '未知错误'));
        var br = document.createElement('br');
        errDiv.appendChild(br);
        errDiv.appendChild(document.createTextNode('请使用手动输入。'));
        el.appendChild(errDiv);
        if (onError) onError(err);
        throw err;
      });
  };

  Html5Qrcode.prototype.stop = function () {
    this.scanning = false;
    if (this.interval) { clearInterval(this.interval); this.interval = null; }
    if (this.stream) {
      this.stream.getTracks().forEach(function (t) { t.stop(); });
      this.stream = null;
    }
    if (this.video) { this.video.srcObject = null; }
  };

  // 修复 L-3：彻底清理（防止 setInterval 后续回调访问已销毁的 detector/stream）
  Html5Qrcode.prototype.clear = function () {
    this.stop();
    if (this.video && this.video.parentNode) {
      this.video.parentNode.removeChild(this.video);
    }
    this.video = null;
    this.detector = null;
  };

  // 修复 L-7：补全静态方法（与 html5-qrcode 兼容）
  Html5Qrcode.getCameras = function () {
    if (!navigator.mediaDevices || !navigator.mediaDevices.enumerateDevices) {
      return Promise.reject(new Error('mediaDevices.enumerateDevices 不可用'));
    }
    return navigator.mediaDevices.enumerateDevices().then(function (devices) {
      return devices
        .filter(function (d) { return d.kind === 'videoinput'; })
        .map(function (d) { return { id: d.deviceId, label: d.label || ('camera-' + d.deviceId.substr(0, 6)) }; });
    });
  };

  Html5Qrcode.isSupported = function () {
    return !!(navigator.mediaDevices && navigator.mediaDevices.getUserMedia && window.BarcodeDetector);
  };

  root.Html5Qrcode = Html5Qrcode;
})(window);
